<script setup>
import { ref, onMounted, onUnmounted } from 'vue'

const hourRotation = ref(0)
const minuteRotation = ref(0)

let intervalId = null

const updateTime = () => {
  const now = new Date()
  const hours = now.getHours() % 12
  const minutes = now.getMinutes()
  const seconds = now.getSeconds()
  
  // Calculate rotation angles
  // Minutes: 6 degrees per minute + 0.1 degrees per second for smooth movement
  minuteRotation.value = (minutes * 6) + (seconds * 0.1)
  
  // Hours: 30 degrees per hour + 0.5 degrees per minute for smooth movement
  hourRotation.value = (hours * 30) + (minutes * 0.5)
}

onMounted(() => {
  updateTime()
  // Update every second
  intervalId = setInterval(updateTime, 1000)
})

onUnmounted(() => {
  if (intervalId) {
    clearInterval(intervalId)
  }
})
</script>

<style scoped>
#hr {
  transform-origin: 105.25px 105.25px;
  transform: translate(-20px, -20px) rotate(v-bind(hourRotation + 'deg'));
  transition: transform 0.3s ease-out;
}

#min {
  transform-origin: 105.25px 105.25px;
  transform: translate(-20px, -20px) rotate(v-bind(minuteRotation + 'deg'));
  transition: transform 0.3s ease-out;
}
</style>
